ooc_processes = [p for p in process_list if p["is_OOC"]]
ooc_count = len(ooc_processes)

# Get unique APC IDs from OOC batches
ooc_apc_ids = set()
for p in ooc_processes:
    if p["apc"]:
        ooc_apc_ids.add(p["apc"])

# Check if all OOC are from same APC
same_apc = len(ooc_apc_ids) == 1 and ooc_count > 0

# Build process table with required columns
process_table = []
for p in process_list:
    process_table.append({
        "tool": p["tool"],
        "step": p["step"],
        "APC": p["apc"],
        "is_OOC": p["is_OOC"]
    })

